handle-readonly-ioexception-on-saveinfo.code:
try
{
    pdfInfo.SaveNewInfo(outputPath);
}
catch (IOException ex) when (IsReadOnlyAttributeError(ex) || IsAccessDenied(ex))
{
    TryClearReadOnly(outputPath);
    pdfInfo.SaveNewInfo(outputPath); // retry
}

static bool IsReadOnlyAttributeError(IOException ex) =>
    ex.Message.IndexOf("read-only", StringComparison.OrdinalIgnoreCase) >= 0;

static bool IsAccessDenied(IOException ex) =>
    ex.HResult == unchecked((int)0x80070005); // ACCESS_DENIED

static void TryClearReadOnly(string path)
{
    if (File.Exists(path))
    {
        var attrs = File.GetAttributes(path);
        if ((attrs & FileAttributes.ReadOnly) == FileAttributes.ReadOnly)
            File.SetAttributes(path, attrs & ~FileAttributes.ReadOnly);
    }
}

